// Dead keys: the Social Media page's teaser column moved to /admin/contentpilot.
const REMOVE_SOCIAL = [
  "comingSoon", "aiPostsTitle", "aiPostsBody", "tierGated",
  "roadmapScheduleTitle", "roadmapScheduleBody",
  "roadmapTemplateTitle", "roadmapTemplateBody",
  "roadmapAutoTitle", "roadmapAutoBody", "currentTier",
];

function setDeep(obj: Record<string, unknown>, key: string, value: string) {
  const parts = key.split(".");
  let cur: Record<string, unknown> = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    const p = parts[i];
    if (typeof cur[p] !== "object" || cur[p] === null || Array.isArray(cur[p])) cur[p] = {};
    cur = cur[p] as Record<string, unknown>;
  }
  cur[parts[parts.length - 1]] = value;
}

let n = 0;
for (const f of readdirSync(DIR).filter((x) => x.endsWith(".json"))) {
  const loc = f.replace(".json", "");
  const path = join(DIR, f);
  const data = JSON.parse(readFileSync(path, "utf8")) as Record<string, any>;
  for (const [k, byLoc] of Object.entries(KEYS)) setDeep(data, k, byLoc[loc] ?? byLoc.en);
  const sm = data?.admin?.socialMedia;
  if (sm && typeof sm === "object") for (const k of REMOVE_SOCIAL) delete sm[k];
  writeFileSync(path, JSON.stringify(data, null, 2) + "\n", "utf8");
  n++;
}
console.log(`✓ contentpilot+sms strings (${Object.keys(KEYS).length} keys) added, ${REMOVE_SOCIAL.length} dead social keys removed, ${n} locale(s).`);
